select CASE WHEN COUNT(*) = 0 THEN 1 ELSE MAX(reg_seq)+1 END AS reg_seq
from   tb_move_req
where  move_reg_date = #{moveRegDate}

WITH item_summary AS ( SELECT b.move_stock_id , MIN(b.item_cd) AS rep_item_cd , SUM(b.qty) AS qty , COUNT(DISTINCT b.item_cd) AS item_cnt FROM tb_move_item b where b.type_cd ='Q' GROUP BY b.move_stock_id ), rep_item AS ( SELECT s.move_stock_id , c.item_name AS rep_item_name , s.qty , s.item_cnt FROM item_summary s INNER JOIN tb_item_mst c ON s.rep_item_cd = c.item_cd ) SELECT CONCAT(CONVERT(varchar(10), a.move_req_date, 23), ' - ', a.seq) AS moveReqDateSeq , c.storage_name as src_storage_name , d.storage_name as tar_storage_name , b.member_nm as manager_name , dbo.getCommonName('MOVE_STATUS', a.move_status) as move_status_name , a.src_storage_cd , a.tar_storage_cd , CASE WHEN r.item_cnt > 1 THEN CONCAT(r.rep_item_name, ' 외 ', r.item_cnt - 1, '건') ELSE r.rep_item_name END AS item_name , a.memo , r.qty , a.manager_id , a.move_status , a.move_stock_id FROM tb_move_stock_mst a INNER JOIN rep_item r ON a.move_stock_id = r.move_stock_id inner join tb_users b on a.manager_id = b.user_id inner join tb_storage_mst c on a.src_storage_cd = c.storage_cd inner join tb_storage_mst d on a.tar_storage_cd = d.storage_cd WHERE a.move_req_date BETWEEN #{strDate} AND #{endDate}
AND a.area_cd = #{areaCd}
AND a.move_status = #{moveStatus}
AND a.src_storage_cd = #{srcStorageCd}
AND a.tar_storage_cd = #{tarStorageCd}
AND EXISTS (SELECT 1 FROM tb_move_req_item b WHERE b.move_stock_id = a.move_stock_id AND b.item_cd LIKE '%' + #{itemCd} + '%' )
AND EXISTS (SELECT 1 FROM tb_move_req_item b INNER JOIN tb_item_mst c ON b.item_cd = c.item_cd WHERE b.move_stock_id = a.move_stock_id AND c.item_name LIKE '%' + #{itemName} + '%' )
ORDER BY a.move_req_date DESC, a.seq DESC

SELECT x.item_cd ,x.test_no ,( SELECT MIN(m2.tran_date) FROM tb_inv_tran_item i2 JOIN tb_inv_tran_mst m2 ON i2.tran_id = m2.tran_id WHERE i2.item_cd = x.item_cd AND i2.test_no = x.test_no AND m2.area_cd = #{areaCd} AND m2.tran_status = 'C' AND m2.tran_type_cd = 'A' ) AS tran_date ,x.storage_cd ,SUM(x.qty) AS qty FROM ( /* src 창고 기준 */ SELECT i.item_cd ,i.test_no ,m.src_storage_cd AS storage_cd ,CASE WHEN m.tran_type_cd IN ('I','J','L','D','E','F','G','Q','T') THEN i.qty * -1 WHEN m.tran_type_cd IN ('A','B','C','P','R','S','U','V','W','X') THEN i.qty ELSE 0 END AS qty FROM tb_inv_tran_item i JOIN tb_inv_tran_mst m ON i.tran_id = m.tran_id WHERE i.item_cd = #{itemCd} AND m.area_cd = #{areaCd} AND m.tran_status = 'C' AND m.src_storage_cd IS NOT NULL UNION ALL /* tar 창고 기준: 이동 입고 */ SELECT i.item_cd ,i.test_no ,m.tar_storage_cd AS storage_cd ,i.qty AS qty FROM tb_inv_tran_item i JOIN tb_inv_tran_mst m ON i.tran_id = m.tran_id WHERE i.item_cd = #{itemCd} AND m.area_cd = #{areaCd} AND m.tran_status = 'C' AND m.tar_storage_cd IS NOT NULL AND m.tran_type_cd IN ('I','J','L') ) x WHERE x.storage_cd = #{storageCd} GROUP BY x.item_cd, x.test_no, x.storage_cd
HAVING SUM(x.qty) <> 0
ORDER BY tran_date, x.item_cd,x.test_no;

