update tb_move_stock_mst
set    move_reg_date    = #{moveReqDate}
      ,reg_seq          = #{regSeq}
      ,move_manager_id  = #{moveManagerId}
      ,confirmer_id     = #{confirmerId}
      ,etc              = #{etc}
      ,move_status      = #{moveStatus}
      ,upd_id           = #{userId}
      ,upd_dt           = getdate()
where  move_stock_id    = #{moveStockId}

UPDATE tb_move_item
SET item_type_cd = #{itemTypeCd}
  , item_cd      = #{itemCd}
  , test_no      = #{testNo}
  , qty          = #{qty}
  , lot_no       = #{lotNo}
  , upd_id       = #{userId}
  , upd_dt       = GETDATE()
WHERE move_item_id = #{moveItemId}
and
